// CAPA 2 - NORMALIZER: Transform Yahoo response to standard schema
const body = $input.first().json.body;
const quotes = body?.quoteResponse?.result || [];

const normalizeSymbol = (symbol) => {
  return symbol
    .replace(/=X$/, '')
    .replace(/=F$/, '')
    .replace(/-USD$/, '')
    .replace(/\^/, '');
};

const normalized = quotes.map(q => ({
  symbol: normalizeSymbol(q.symbol),
  price: q.regularMarketPrice ?? null,
  change_pct_1d: q.regularMarketChangePercent ?? 0,
  high_1d: q.regularMarketDayHigh ?? null,
  low_1d: q.regularMarketDayLow ?? null,
  volume: q.regularMarketVolume ?? 0,
  source: 'yahoo_finance',
  delay_minutes: 15,
  timestamp: new Date(q.regularMarketTime * 1000).toISOString(),
  raw_symbol: q.symbol,
  currency: q.currency ?? null,
  market_state: q.marketState ?? 'REGULAR'
}));

return normalized.map(n => ({ json: n }));

// CAPA 2b - ENRICH: Add trend indicators and alert levels
const instruments = $input.all();

const getTrend = (changePct) => {
  if (changePct > 0.1) return 'UP';
  if (changePct < -0.1) return 'DOWN';
  return 'FLAT';
};

const isForex = (symbol) => {
  const forexPairs = ['EURUSD', 'GBPUSD', 'USDJPY', 'USDCHF', 'AUDUSD', 'USDCAD', 'NZDUSD', 'EURGBP', 'EURJPY', 'GBPJPY'];
  return forexPairs.includes(symbol);
};

const isIndex = (symbol) => {
  const indices = ['GSPC', 'NDX', 'DJI', 'VIX', 'FTSE', 'GDAXI', 'N225', 'ES', 'NQ'];
  return indices.some(i => symbol.includes(i));
};

const getAlertLevel = (item) => {
  const change = Math.abs(item.json.change_pct_1d || 0);
  const isIdx = isIndex(item.json.symbol);
  const isFx = isForex(item.json.symbol);

  // ALERT thresholds
  if (change > 3) return 'ALERT';
  if (isIdx && change > 3) return 'ALERT';
  if (isFx && change > 2) return 'ALERT';
  if (isIdx && change > 2) return 'ALERT';

  // WATCH thresholds
  if (isFx && change > 1) return 'WATCH';
  if (isIdx && change > 2) return 'WATCH';
  if (change > 2) return 'WATCH';

  return 'NORMAL';
};

const enriched = instruments.map(item => {
  const enrichedItem = { ...item.json };
  enrichedItem.trend_1d = getTrend(enrichedItem.change_pct_1d);
  enrichedItem.alert_level = getAlertLevel(item);
  return { json: enrichedItem };
});

return enriched;

// CAPA 3 - BUILD SNAPSHOT: Human-readable price snapshot
const data = $input.all();
const now = new Date();

const formatPrice = (price, decimals = 2) => {
  if (price == null) return 'N/A';
  return price.toFixed(decimals);
};

const formatChange = (change) => {
  if (change == null) return '0.00%';
  const sign = change >= 0 ? '+' : '';
  return `${sign}${change.toFixed(2)}%`;
};

const getAlertIcon = (level) => {
  if (level === 'ALERT') return '🚨';
  if (level === 'WATCH') return '⚠️';
  return '';
};

// Group by category
const forex = data.filter(d => ['EURUSD', 'GBPUSD', 'USDJPY', 'USDCHF', 'AUDUSD', 'USDCAD', 'NZDUSD', 'EURGBP', 'EURJPY', 'GBPJPY'].includes(d.json.symbol));
const indices = data.filter(d => ['GSPC', 'NDX', 'DJI', 'FTSE', 'GDAXI', 'N225'].some(i => d.json.symbol.includes(i)));
const vix = data.find(d => d.json.symbol === 'VIX');
const futures = data.filter(d => ['ES', 'NQ', 'CL', 'GC', 'SI', 'NG', 'ZC'].some(f => d.json.symbol.startsWith(f)));
const crypto = data.filter(d => ['BTC', 'ETH', 'SOL', 'BNB'].some(c => d.json.symbol.startsWith(c)));
const dxy = data.find(d => d.json.symbol.includes('DX'));
const yields = data.filter(d => ['TNX', 'TYX', 'IRX'].some(y => d.json.symbol.includes(y)));
const alerts = data.filter(d => d.json.alert_level !== 'NORMAL');

let snapshot = `SNAPSHOT DE PRECIO — ${now.toLocaleDateString('es-ES')} ${now.toLocaleTimeString('es-ES', { hour: '2-digit', minute: '2-digit' })} (delay ~15min)\n\n`;

// FOREX
snapshot += 'FOREX:\n';
forex.forEach(f => {
  const icon = getAlertIcon(f.json.alert_level);
  snapshot += `• ${f.json.symbol}: ${formatPrice(f.json.price, 4)} (${formatChange(f.json.change_pct_1d)}) H:${formatPrice(f.json.high_1d, 4)} L:${formatPrice(f.json.low_1d, 4)} ${icon}\n`;
});

// ALERTAS DE MOVIMIENTO
if (alerts.length > 0) {
  snapshot += '\nALERTAS DE MOVIMIENTO:\n';
  alerts.forEach(a => {
    const icon = getAlertIcon(a.json.alert_level);
    snapshot += `• ${a.json.symbol}: ${formatPrice(a.json.price)} — movimiento de ${Math.abs(a.json.change_pct_1d).toFixed(1)}% en el día ${icon}\n`;
  });
}

// INDICES & MACRO
snapshot += '\nÍNDICES & MACRO:\n';
indices.forEach(i => {
  snapshot += `• ${i.json.symbol}: ${formatPrice(i.json.price)} (${formatChange(i.json.change_pct_1d)})\n`;
});
if (vix) {
  const vixLevel = vix.json.price < 15 ? 'LOW' : vix.json.price < 25 ? 'MEDIUM' : 'HIGH';
  snapshot += `• VIX: ${formatPrice(vix.json.price)} (${vixLevel})\n`;
}
if (dxy) {
  snapshot += `• DXY: ${formatPrice(dxy.json.price)} (${formatChange(dxy.json.change_pct_1d)})\n`;
}

// YIELDS
if (yields.length > 0) {
  snapshot += '\nYIELDS:\n';
  yields.forEach(y => {
    snapshot += `• ${y.json.symbol}: ${formatPrice(y.json.price)}%\n`;
  });
}

// MATERIAS PRIMAS (Futures)
if (futures.length > 0) {
  snapshot += '\nMATERIAS PRIMAS:\n';
  futures.forEach(f => {
    snapshot += `• ${f.json.symbol}: ${formatPrice(f.json.price)} (${formatChange(f.json.change_pct_1d)})\n`;
  });
}

// CRYPTO
if (crypto.length > 0) {
  snapshot += '\nCRYPTO:\n';
  crypto.forEach(c => {
    snapshot += `• ${c.json.symbol}: ${formatPrice(c.json.price)} (${formatChange(c.json.change_pct_1d)})\n`;
  });
}

return [{ json: { snapshot, timestamp: now.toISOString() } }];

// Filter only WATCH and ALERT items
const data = $input.all();
const alerts = data.filter(d => d.json.alert_level !== 'NORMAL');
return alerts;

// Respond with the snapshot text
const snapshotData = $('Build Snapshot').first().json;
return [{ json: { snapshot: snapshotData.snapshot, timestamp: snapshotData.timestamp } }];

// Respond with raw normalized data
const allData = $('Enrich').all();
return allData;

// Respond with filtered alerts only
const alertsData = $('Filter Alerts').all();
return alertsData;

// Respond with specific symbol data
const symbol = $('Webhook /price/{symbol}').first().json.query?.symbol || $('Webhook /price/{symbol}').first().json.symbol;
const allData = $('Enrich').all();
const found = allData.find(d => d.json.symbol.toUpperCase() === (symbol || '').toUpperCase());
return found ? [found] : [{ json: { error: 'Symbol not found', symbol } }];

// Route ALERT items to alert webhook
const allData = $('Enrich').all();
const alertItems = allData.filter(d => d.json.alert_level === 'ALERT');
return alertItems;

// Merge snapshot text into a file-compatible format
const snapshotNode = $('Build Snapshot').first().json;
return [{ json: { text: snapshotNode.snapshot, timestamp: snapshotNode.timestamp } }];

// Prepare data for latest JSON storage
const allData = $('Enrich').all();
return [{ json: { prices: allData.map(d => d.json), timestamp: new Date().toISOString() } }];

// Prepare alerts JSON
const alertsData = $('Filter Alerts').all();
return [{ json: { alerts: alertsData.map(d => d.json), timestamp: new Date().toISOString() } }];
